package com.example.self_introduction

import android.os.Bundle
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.activity.enableEdgeToEdge
import androidx.compose.foundation.layout.fillMaxSize
import androidx.compose.foundation.layout.padding
import androidx.compose.material3.Scaffold
import androidx.compose.material3.Text
import androidx.compose.runtime.Composable
import androidx.compose.ui.Modifier
import androidx.compose.ui.tooling.preview.Preview
import com.example.self_introduction.ui.theme.Self_IntroductionTheme

class MainActivity : ComponentActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContent {
            Self_IntroductionTheme {
                Scaffold(modifier = Modifier.fillMaxSize()) { innerPadding ->
                    Greeting(
                        name = "Android",
                        modifier = Modifier.padding(innerPadding)
                    )
                }
            }
        }
    }
}

@Composable
fun Greeting(name: String, modifier: Modifier = Modifier) {
    Text(
        text = "Hello $name!",
        modifier = modifier
    )
}

@Preview(showBackground = true)
@Composable
fun GreetingPreview() {
    Self_IntroductionTheme {
        Greeting("Android")
    }
}

package com.example.self_introduction
import android.os.Bundle import android.view.View import androidx.appcompat.app.AppCompatActivity import androidx.navigation.fragment.NavHostFragment import androidx.navigation.ui.setupWithNavController import com.example.self_introduction.databinding.ActivityMainBinding
class MainActivity : AppCompatActivity() {
private lateinit var binding: ActivityMainBinding
private val bottomNavDestinations = setOf( R.id.homeFragment, R.id.skillsFragment, R.id.projectsFragment, R.id.journeyFragment )
override fun onCreate(savedInstanceState: Bundle?) { super.onCreate(savedInstanceState) binding = ActivityMainBinding.inflate(layoutInflater) setContentView(binding.root)
val navHostFragment = supportFragmentManager .findFragmentById(R.id.nav_host_fragment) as NavHostFragment val navController = navHostFragment.navController
binding.bottomNav.setupWithNavController(navController)
navController.addOnDestinationChangedListener { _, destination, _ -> binding.bottomNav.visibility = if (destination.id in bottomNavDestinations) View.VISIBLE else View.GONE } } }

package com.example.self_introduction.adapter

import android.content.Intent
import android.net.Uri
import android.view.LayoutInflater
import android.view.ViewGroup
import androidx.recyclerview.widget.RecyclerView
import com.example.self_introduction.databinding.ItemProjectBinding
import com.example.self_introduction.model.Project
import com.google.android.material.chip.Chip

class ProjectsAdapter(private var projects: List<Project>) :
    RecyclerView.Adapter<ProjectsAdapter.ProjectViewHolder>() {

    inner class ProjectViewHolder(val binding: ItemProjectBinding) :
        RecyclerView.ViewHolder(binding.root)

    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): ProjectViewHolder {
        val binding = ItemProjectBinding.inflate(LayoutInflater.from(parent.context), parent, false)
        return ProjectViewHolder(binding)
    }

    override fun onBindViewHolder(holder: ProjectViewHolder, position: Int) {
        val project = projects[position]
        with(holder.binding) {
            tvProjectTitle.text = project.title
            tvProjectDesc.text = project.description

            chipGroupTech.removeAllViews()
            project.techStack.forEach { tech ->
                val chip = Chip(chipGroupTech.context).apply {
                    text = tech
                    isClickable = false
                }
                chipGroupTech.addView(chip)
            }

            btnGithub.setOnClickListener {
                val intent = Intent(Intent.ACTION_VIEW, Uri.parse(project.githubUrl))
                it.context.startActivity(intent)
            }
        }
    }

    override fun getItemCount() = projects.size

    fun updateProjects(newProjects: List<Project>) {
        projects = newProjects
        notifyDataSetChanged()
    }
}

package com.example.self_introduction.ui

import android.os.Bundle
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.fragment.app.Fragment
import androidx.fragment.app.viewModels
import androidx.lifecycle.lifecycleScope
import com.example.self_introduction.databinding.FragmentAboutBinding
import com.example.self_introduction.viewmodel.ProfileViewModel
import kotlinx.coroutines.launch

class AboutFragment : Fragment() {

    private var _binding: FragmentAboutBinding? = null
    private val binding get() = _binding!!
    private val viewModel: ProfileViewModel by viewModels()

    override fun onCreateView(inflater: LayoutInflater, container: ViewGroup?, savedInstanceState: Bundle?): View {
        _binding = FragmentAboutBinding.inflate(inflater, container, false)
        return binding.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        viewLifecycleOwner.lifecycleScope.launch {
            launch { viewModel.name.collect { binding.tvAboutName.text = "About $it" } }
            launch { viewModel.bio.collect { binding.tvBio.text = it } }
            launch { viewModel.quote.collect { binding.tvQuote.text = it } }
        }

        binding.socialLinks.setLinks(viewModel.githubUrl, viewModel.linkedinUrl, viewModel.emailAddress)
    }

    override fun onDestroyView() {
        super.onDestroyView()
        _binding = null
    }
}

package com.example.self_introduction.ui

import android.os.Bundle
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.fragment.app.Fragment
import com.example.self_introduction.databinding.FragmentChinchiroBinding

class ChinchiroFragment : Fragment() {

    private var _binding: FragmentChinchiroBinding? = null
    private val binding get() = _binding!!

    private val diceFaces = listOf("⚀", "⚁", "⚂", "⚃", "⚄", "⚅")

    override fun onCreateView(inflater: LayoutInflater, container: ViewGroup?, savedInstanceState: Bundle?): View {
        _binding = FragmentChinchiroBinding.inflate(inflater, container, false)
        return binding.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        binding.btnRoll.setOnClickListener {
            val d1 = (1..6).random()
            val d2 = (1..6).random()
            val d3 = (1..6).random()

            binding.tvDice1.text = diceFaces[d1 - 1]
            binding.tvDice2.text = diceFaces[d2 - 1]
            binding.tvDice3.text = diceFaces[d3 - 1]

            binding.tvResult.text = evaluateRoll(d1, d2, d3)
        }
    }

    private fun evaluateRoll(d1: Int, d2: Int, d3: Int): String {
        val dice = listOf(d1, d2, d3).sorted()
        return when {
            dice == listOf(4, 5, 6) -> " Shichi-Go-San! You win!"
            dice == listOf(1, 2, 3) -> " Pichi! You lose!"
            d1 == d2 && d2 == d3 -> " Triple ${dice[0]}! Amazing!"
            d1 == d2 || d2 == d3 || d1 == d3 -> {
                val pair = if (d1 == d2) d1 else if (d2 == d3) d2 else d1
                val odd = listOf(d1, d2, d3).first { it != pair }
                " Pair of $pair — Point: $odd"
            }
            else -> " No combination... Try again!"
        }
    }

    override fun onDestroyView() {
        super.onDestroyView()
        _binding = null
    }
}

package com.example.self_introduction.ui

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.Toast
import androidx.fragment.app.Fragment
import androidx.fragment.app.viewModels
import androidx.lifecycle.lifecycleScope
import com.example.self_introduction.databinding.FragmentContactBinding
import com.example.self_introduction.viewmodel.ContactViewModel
import kotlinx.coroutines.launch

class ContactFragment : Fragment() {

    private var _binding: FragmentContactBinding? = null
    private val binding get() = _binding!!
    private val viewModel: ContactViewModel by viewModels()

    private val recipientEmail = "your.email@example.com"

    override fun onCreateView(inflater: LayoutInflater, container: ViewGroup?, savedInstanceState: Bundle?): View {
        _binding = FragmentContactBinding.inflate(inflater, container, false)
        return binding.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        binding.btnSend.setOnClickListener {
            val name = binding.etSenderName.text?.toString() ?: ""
            val email = binding.etSenderEmail.text?.toString() ?: ""
            val message = binding.etMessage.text?.toString() ?: ""

            if (name.isBlank() || email.isBlank() || message.isBlank()) {
                Toast.makeText(requireContext(), "Please fill in all fields", Toast.LENGTH_SHORT).show()
                return@setOnClickListener
            }

            val subject = "Portfolio Contact from $name"
            val body = "From: $name\nEmail: $email\n\n$message"

            val intent = Intent(Intent.ACTION_SENDTO).apply {
                data = Uri.parse("mailto:$recipientEmail")
                putExtra(Intent.EXTRA_SUBJECT, subject)
                putExtra(Intent.EXTRA_TEXT, body)
            }
            startActivity(intent)
        }

        viewLifecycleOwner.lifecycleScope.launch {
            viewModel.formState.collect { state ->
                if (state.isSent) {
                    Toast.makeText(requireContext(), "Message sent!", Toast.LENGTH_SHORT).show()
                    viewModel.resetSent()
                }
            }
        }
    }

    override fun onDestroyView() {
        super.onDestroyView()
        _binding = null
    }
}

package com.example.self_introduction.ui

import android.os.Bundle
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.fragment.app.Fragment
import androidx.fragment.app.viewModels
import androidx.lifecycle.lifecycleScope
import androidx.navigation.fragment.findNavController
import com.example.self_introduction.R
import com.example.self_introduction.databinding.FragmentHomeBinding
import com.example.self_introduction.viewmodel.ProfileViewModel
import kotlinx.coroutines.launch

class HomeFragment : Fragment() {

    private var _binding: FragmentHomeBinding? = null
    private val binding get() = _binding!!
    private val viewModel: ProfileViewModel by viewModels()
    private var tapCount = 0

    override fun onCreateView(inflater: LayoutInflater, container: ViewGroup?, savedInstanceState: Bundle?): View {
        _binding = FragmentHomeBinding.inflate(inflater, container, false)
        return binding.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        viewLifecycleOwner.lifecycleScope.launch {
            launch {
                viewModel.name.collect { binding.tvName.text = it }
            }
            launch {
                viewModel.tagline.collect { binding.tvTagline.text = it }
            }
            launch {
                viewModel.stats.collect { stats ->
                    binding.tvStatProjectsCount.text = stats.projectCount.toString()
                    binding.tvStatSkillsCount.text = stats.skillCount.toString()
                    binding.tvStatYearsCount.text = stats.yearsExperience.toString()
                }
            }
        }

        binding.socialLinks.setLinks(viewModel.githubUrl, viewModel.linkedinUrl, viewModel.emailAddress)

        binding.btnAboutMe.setOnClickListener {
            findNavController().navigate(R.id.action_home_to_about)
        }

        binding.btnContact.setOnClickListener {
            findNavController().navigate(R.id.action_home_to_contact)
        }

        // Easter egg: tap 5 times on the hidden emoji
        binding.tvEasterEgg.setOnClickListener {
            tapCount++
            if (tapCount >= 5) {
                tapCount = 0
                findNavController().navigate(R.id.action_home_to_chinchiro)
            }
        }
    }

    override fun onDestroyView() {
        super.onDestroyView()
        _binding = null
    }
}

package com.example.self_introduction.ui

import android.os.Bundle
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.fragment.app.Fragment
import androidx.fragment.app.viewModels
import com.example.self_introduction.databinding.FragmentJourneyBinding
import com.example.self_introduction.databinding.ItemTimelineBinding
import com.example.self_introduction.viewmodel.ProfileViewModel

class JourneyFragment : Fragment() {

    private var _binding: FragmentJourneyBinding? = null
    private val binding get() = _binding!!
    private val viewModel: ProfileViewModel by viewModels()

    override fun onCreateView(inflater: LayoutInflater, container: ViewGroup?, savedInstanceState: Bundle?): View {
        _binding = FragmentJourneyBinding.inflate(inflater, container, false)
        return binding.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        val events = viewModel.timeline
        binding.timelineContainer.removeAllViews()

        events.forEachIndexed { index, event ->
            val itemBinding = ItemTimelineBinding.inflate(layoutInflater, binding.timelineContainer, false)
            itemBinding.tvYear.text = event.year
            itemBinding.tvTimelineTitle.text = event.title
            itemBinding.tvTimelineDesc.text = event.description
            // Hide line for last item
            if (index == events.lastIndex) {
                itemBinding.line.visibility = View.INVISIBLE
            }
            binding.timelineContainer.addView(itemBinding.root)
        }
    }

    override fun onDestroyView() {
        super.onDestroyView()
        _binding = null
    }
}

package com.example.self_introduction.ui

import android.os.Bundle
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.fragment.app.Fragment
import androidx.fragment.app.viewModels
import androidx.lifecycle.lifecycleScope
import androidx.recyclerview.widget.LinearLayoutManager
import com.example.self_introduction.adapter.ProjectsAdapter
import com.example.self_introduction.databinding.FragmentProjectsBinding
import com.example.self_introduction.viewmodel.ProjectsViewModel
import kotlinx.coroutines.launch

class ProjectsFragment : Fragment() {

    private var _binding: FragmentProjectsBinding? = null
    private val binding get() = _binding!!
    private val viewModel: ProjectsViewModel by viewModels()
    private lateinit var adapter: ProjectsAdapter

    override fun onCreateView(inflater: LayoutInflater, container: ViewGroup?, savedInstanceState: Bundle?): View {
        _binding = FragmentProjectsBinding.inflate(inflater, container, false)
        return binding.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        adapter = ProjectsAdapter(emptyList())
        binding.recyclerProjects.layoutManager = LinearLayoutManager(requireContext())
        binding.recyclerProjects.adapter = adapter

        viewLifecycleOwner.lifecycleScope.launch {
            viewModel.projects.collect { projects ->
                adapter.updateProjects(projects)
            }
        }
    }

    override fun onDestroyView() {
        super.onDestroyView()
        _binding = null
    }
}

package com.example.self_introduction.ui

import android.os.Bundle
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.TextView
import androidx.fragment.app.Fragment
import androidx.fragment.app.viewModels
import com.example.self_introduction.databinding.FragmentSkillsBinding
import com.example.self_introduction.model.Skill
import com.example.self_introduction.viewmodel.ProfileViewModel
import com.google.android.material.chip.Chip
import com.google.android.material.chip.ChipGroup

class SkillsFragment : Fragment() {

    private var _binding: FragmentSkillsBinding? = null
    private val binding get() = _binding!!
    private val viewModel: ProfileViewModel by viewModels()

    override fun onCreateView(inflater: LayoutInflater, container: ViewGroup?, savedInstanceState: Bundle?): View {
        _binding = FragmentSkillsBinding.inflate(inflater, container, false)
        return binding.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)
        renderSkills(viewModel.skills)
    }

    private fun renderSkills(skills: List<Skill>) {
        val grouped = skills.groupBy { it.category }
        binding.skillsContainer.removeAllViews()

        grouped.forEach { (category, skillList) ->
            // Category label
            val label = TextView(requireContext()).apply {
                text = category
                textSize = 18f
                setTypeface(null, android.graphics.Typeface.BOLD)
                setPadding(0, 24, 0, 8)
            }
            binding.skillsContainer.addView(label)

            // ChipGroup for skills
            val chipGroup = ChipGroup(requireContext()).apply {
                layoutParams = ViewGroup.LayoutParams(
                    ViewGroup.LayoutParams.MATCH_PARENT,
                    ViewGroup.LayoutParams.WRAP_CONTENT
                )
            }
            skillList.forEach { skill ->
                val chip = Chip(requireContext()).apply {
                    text = skill.name
                    isClickable = false
                    isCheckable = false
                }
                chipGroup.addView(chip)
            }
            binding.skillsContainer.addView(chipGroup)
        }
    }

    override fun onDestroyView() {
        super.onDestroyView()
        _binding = null
    }
}

package com.example.self_introduction.view

import android.content.Context
import android.content.Intent
import android.net.Uri
import android.util.AttributeSet
import android.view.LayoutInflater
import android.widget.LinearLayout
import com.example.self_introduction.databinding.ViewSocialLinksBinding

class SocialLinksView @JvmOverloads constructor(
    context: Context,
    attrs: AttributeSet? = null,
    defStyleAttr: Int = 0
) : LinearLayout(context, attrs, defStyleAttr) {

    private val binding = ViewSocialLinksBinding.inflate(LayoutInflater.from(context), this, true)

    var githubUrl: String = "https://github.com/yourusername"
    var linkedinUrl: String = "https://linkedin.com/in/yourusername"
    var emailAddress: String = "your.email@example.com"

    init {
        binding.btnGithub.setOnClickListener { openUrl(githubUrl) }
        binding.btnLinkedin.setOnClickListener { openUrl(linkedinUrl) }
        binding.btnEmail.setOnClickListener { sendEmail() }
    }

    fun setLinks(github: String, linkedin: String, email: String) {
        githubUrl = github
        linkedinUrl = linkedin
        emailAddress = email
        binding.btnGithub.setOnClickListener { openUrl(githubUrl) }
        binding.btnLinkedin.setOnClickListener { openUrl(linkedinUrl) }
        binding.btnEmail.setOnClickListener { sendEmail() }
    }

    private fun openUrl(url: String) {
        val intent = Intent(Intent.ACTION_VIEW, Uri.parse(url))
        context.startActivity(intent)
    }

    private fun sendEmail() {
        val intent = Intent(Intent.ACTION_SENDTO).apply {
            data = Uri.parse("mailto:$emailAddress")
        }
        context.startActivity(intent)
    }
}

package com.example.self_introduction.viewmodel

import androidx.lifecycle.ViewModel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow

data class ContactFormState(
    val senderName: String = "",
    val senderEmail: String = "",
    val message: String = "",
    val isSent: Boolean = false
)

class ContactViewModel : ViewModel() {

    private val _formState = MutableStateFlow(ContactFormState())
    val formState: StateFlow<ContactFormState> = _formState

    fun updateName(name: String) {
        _formState.value = _formState.value.copy(senderName = name)
    }

    fun updateEmail(email: String) {
        _formState.value = _formState.value.copy(senderEmail = email)
    }

    fun updateMessage(message: String) {
        _formState.value = _formState.value.copy(message = message)
    }

    fun onSendClicked() {
        _formState.value = _formState.value.copy(isSent = true)
    }

    fun resetSent() {
        _formState.value = _formState.value.copy(isSent = false)
    }
}

